mapper.select:
SELECT num, title, writer, CONTENT, hit, reip, cdate, imgn, row_num FROM (SELECT num, title, writer, CONTENT, hit, reip, cdate, imgn, ROW_NUMBER() OVER(ORDER BY num desc) AS row_num FROM community
writer like '%' || #{searchValue} || '%'
title like '%' || #{searchValue} || '%'
content like '%' || #{searchValue} || '%'
) numbered_rows WHERE row_num BETWEEN #{begin} AND #{end}
